INSERT INTO public.documentation_sections (title, description, icon, content, order_index, is_published) VALUES
('Getting Started', 'Learn how to set up and start using our platform quickly', 'Rocket', 'Welcome to our platform! This guide will help you get started with the basics.\n\n## Installation\n\nFollow these simple steps to install and configure the platform.\n\n## Quick Start\n\nOnce installed, you can begin creating your first project in minutes.', 1, true),
('Components Library', 'Explore our extensive collection of reusable UI components', 'Layout', 'Our component library offers a wide range of pre-built, customizable UI elements.\n\n## Available Components\n\n- Buttons\n- Cards\n- Forms\n- Navigation\n- Modals\n\n## Usage\n\nSimply import and use any component in your project.', 2, true),
('Templates Guide', 'Complete templates to jumpstart your projects', 'FileCode', 'Templates are full-featured starting points for your applications.\n\n## Template Categories\n\n- Landing Pages\n- Dashboards\n- E-commerce\n- Portfolios\n\n## Customization\n\nAll templates are fully customizable to match your brand.', 3, true),
('API Reference', 'Detailed documentation for our API endpoints', 'Code', 'Complete API documentation for integrating with our services.\n\n## Authentication\n\nAll API requests require authentication via API keys.\n\n## Endpoints\n\nExplore available endpoints and their parameters.', 4, true),
('Best Practices', 'Tips and recommendations for optimal usage', 'BookOpen', 'Follow these best practices to get the most out of our platform.\n\n## Performance\n\n- Optimize your builds\n- Use lazy loading\n- Minimize bundle size\n\n## Security\n\n- Keep dependencies updated\n- Use environment variables', 5, true),
('FAQ', 'Frequently asked questions and troubleshooting', 'HelpCircle', 'Find answers to common questions.\n\n## Common Issues\n\n**Q: How do I reset my password?**\nA: Visit the settings page and click "Reset Password".\n\n**Q: Can I export my data?**\nA: Yes, you can export all your data from the dashboard.', 6, true);